import requests

def test_hr_admin_delete_with_invalid_payload_returns_400():
    base_url = 'http://localhost:8080'
    headers = {
        'Authorization': 'Bearer <valid_hr_admin_token>',
        'Content-Type': 'application/json'
    }
    review_id = 'PR-2024-004'

    response = requests.delete(
        f'{base_url}/performance-reviews/{review_id}',
        headers=headers,
        json={'invalid_field': 'data'}
    )

    assert response.status_code == 400
    assert 'validation' in response.json()['error'].lower()

    verify_response = requests.get(
        f'{base_url}/performance-reviews/{review_id}',
        headers={'Authorization': 'Bearer <valid_hr_admin_token>'}
    )
    assert verify_response.status_code == 200
